const t={boardTopology:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Découvrez comment les cartes de contrôle de votre imprimante se connectent : l'hôte (SBC) et chaque MCU avec lequel il communique, avec chaque type de connexion et une estimation au mieux de la carte / puce — lue en direct depuis la configuration."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Aide"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"À propos de la topologie des cartes"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Fermer"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Comment lire"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"L'hôte (votre SBC, par ex. un Raspberry Pi ou un CB1) se trouve en haut."}},{t:0,b:{t:2,i:[{t:3}],s:"Chaque carte MCU indique comment elle se connecte (USB / CAN bus / UART) et sa puce."}},{t:0,b:{t:2,i:[{t:3}],s:"Une estimation de la carte apparaît lorsque l'identifiant de connexion correspond à une carte connue."}}],topics:{mcus:{title:{t:0,b:{t:2,i:[{t:3}],s:"MCU"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Un MCU est une carte à microcontrôleur qui pilote les moteurs, les chauffages et les capteurs. Une imprimante en possède au moins un (la carte mère) ; beaucoup ajoutent une carte de tête d'impression et parfois une carte de palpeur ou de LED. Ce panneau liste chaque section `[mcu]` connue de Klipper."}}},connections:{title:{t:0,b:{t:2,i:[{t:3}],s:"Types de connexion"}},body:{t:0,b:{t:2,i:[{t:3}],s:"USB — une liaison série sur USB (la connexion habituelle de la carte mère). CAN bus — un bus partagé à deux fils, courant pour les cartes de tête d'impression. UART — une liaison série directe via GPIO. Le type est déduit du paramètre `serial` / `canbus_uuid` de chaque MCU."}}},detection:{title:{t:0,b:{t:2,i:[{t:3}],s:"Comment fonctionne la détection"}},body:{t:0,b:{t:2,i:[{t:3}],s:"La puce et la carte sont devinées en comparant l’identifiant de connexion (le chemin série ou l’UUID CAN) à une table de motifs, plus une empreinte de la carte des broches utilisées par votre configuration. Une proposition de carte affiche un niveau de correspondance ; si rien ne correspond, la puce/carte affiche « inconnu » — la connexion elle-même reste affichée."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glossaire"}},body:{t:0,b:{static:"",t:2,i:[]}}},override:{title:{t:0,b:{t:2,i:[{t:3}],s:"Confirmer ou changer une carte"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Un identifiant série ne révèle généralement que la puce, donc la carte proposée peut être absente ou erronée. Utilisez « Confirmer cette carte » pour valider une bonne proposition, ou « Changer de carte… » / « Choisir la carte… » pour sélectionner la bonne dans le catalogue. Votre choix est enregistré sur l’hôte et réutilisé à chaque lecture ; « Effacer » rétablit la proposition automatique."}}},views:{title:{t:0,b:{t:2,i:[{t:3}],s:"Vue physique vs logique"}},body:{t:0,b:{t:2,i:[{t:3}],s:"La carte dessine les mêmes cartes de deux façons. PHYSIQUE montre comment la machine est réellement construite : un SBC intégré est dessiné dans la carte mère qui le porte, les têtes CAN pendent d'un bus dorsal partagé et les cartes USB/UART sont des unités séparées. LOGIQUE montre comment Klipper le voit : l'hôte en haut, chaque MCU enfant via son lien série. Basculez avec l'interrupteur Physique/Logique."}}}},glossary:{mcu:{term:{t:0,b:{t:2,i:[{t:3}],s:"MCU"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Microcontroller unit — une carte de contrôle exécutant le firmware de Klipper (carte mère, tête d'impression, etc.)."}}},canbus:{term:{t:0,b:{t:2,i:[{t:3}],s:"CAN bus"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un bus partagé à deux fils reliant les cartes par un UUID unique — populaire pour le câblage des têtes d'impression."}}},host:{term:{t:0,b:{t:2,i:[{t:3}],s:"Hôte / SBC"}},def:{t:0,b:{t:2,i:[{t:3}],s:"L'ordinateur monocarte (Pi, CB1, …) qui exécute Klipper et communique avec les MCU."}}}}},host:{label:{t:0,b:{t:2,i:[{t:3}],s:"Hôte"}},role:{t:0,b:{t:2,i:[{t:3}],s:"Ordinateur monocarte — exécute Klipper"}}},mcu:{chip:{t:0,b:{t:2,i:[{t:3}],s:"Puce"}},board:{t:0,b:{t:2,i:[{t:3}],s:"Carte"}},unknown:{t:0,b:{t:2,i:[{t:3}],s:"inconnu"}},identifier:{t:0,b:{t:2,i:[{t:3}],s:"Identifiant"}},confidence:{t:0,b:{t:2,i:[{t:4,k:"pct"},{t:3,v:" % de correspondance"}]}},viewBoard:{t:0,b:{t:2,i:[{t:3}],s:"Voir les détails de la carte"}},hideBoard:{t:0,b:{t:2,i:[{t:3}],s:"Masquer les détails"}}},conn:{canbus:{t:0,b:{t:2,i:[{t:3}],s:"CAN bus"}},usb:{t:0,b:{t:2,i:[{t:3}],s:"USB"}},uart:{t:0,b:{t:2,i:[{t:3}],s:"UART"}},unknown:{t:0,b:{t:2,i:[{t:3}],s:"inconnu"}},via:{t:0,b:{t:2,i:[{t:3,v:"via "},{t:4,k:"type"}]}}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" MCU"}]}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Lecture de la topologie…"}},unreachable:{t:0,b:{t:2,i:[{t:3}],s:"Impossible de joindre l'imprimante."}},empty:{t:0,b:{t:2,i:[{t:3}],s:"Aucun MCU trouvé dans la configuration."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Réessayer"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"Actualiser"}}},board:{suggested:{t:0,b:{t:2,i:[{t:3}],s:"suggéré"}},ports:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" ports"}]}},specsTitle:{t:0,b:{t:2,i:[{t:3}],s:"Caractéristiques"}},portsTitle:{t:0,b:{t:2,i:[{t:3}],s:"Ports"}},none:{t:0,b:{t:2,i:[{t:3}],s:"Pas encore de détails de catalogue pour cette carte."}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Chargement de la carte…"}},links:{title:{t:0,b:{t:2,i:[{t:3}],s:"Liens"}},product:{t:0,b:{t:2,i:[{t:3}],s:"Produit"}},repo:{t:0,b:{t:2,i:[{t:3}],s:"Dépôt"}},wiki:{t:0,b:{t:2,i:[{t:3}],s:"Wiki"}},pinout:{t:0,b:{t:2,i:[{t:3}],s:"Brochage"}},schematic:{t:0,b:{t:2,i:[{t:3}],s:"Schéma"}},datasheet:{t:0,b:{t:2,i:[{t:3}],s:"Fiche technique"}},image:{t:0,b:{t:2,i:[{t:3}],s:"Photo"}}},noMatch:{t:0,b:{t:2,i:[{t:3}],s:"Aucune carte correspondante pour l'instant — confirmez ou choisissez-en une ci-dessous."}}},components:{title:{t:0,b:{t:2,i:[{t:3}],s:"Composants"}},motor:{t:0,b:{t:2,i:[{t:3}],s:"Moteurs"}},driver:{t:0,b:{t:2,i:[{t:3}],s:"Drivers"}},heater:{t:0,b:{t:2,i:[{t:3}],s:"Chauffages"}},fan:{t:0,b:{t:2,i:[{t:3}],s:"Ventilateurs"}},sensor:{t:0,b:{t:2,i:[{t:3}],s:"Capteurs"}}},sync:{synced:{t:0,b:{t:2,i:[{t:3}],s:"Firmware synchronisé"}},outOfSync:{t:0,b:{t:2,i:[{t:3}],s:"Firmware DÉSYNCHRONISÉ"}}},override:{confirmed:{t:0,b:{t:2,i:[{t:3}],s:"Confirmé par vous"}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Confirmer cette carte"}},change:{t:0,b:{t:2,i:[{t:3}],s:"Changer de carte…"}},set:{t:0,b:{t:2,i:[{t:3}],s:"Choisir la carte…"}},clear:{t:0,b:{t:2,i:[{t:3}],s:"Effacer"}},pickPlaceholder:{t:0,b:{t:2,i:[{t:3}],s:"Rechercher dans le catalogue de cartes…"}},hint:{t:0,b:{t:2,i:[{t:3}],s:"Votre choix est enregistré sur l’hôte et utilisé pour ce MCU désormais."}}},graph:{viewLabel:{t:0,b:{t:2,i:[{t:3}],s:"Vue du schéma"}},view:{physical:{t:0,b:{t:2,i:[{t:3}],s:"Physique"}},logical:{t:0,b:{t:2,i:[{t:3}],s:"Logique"}}},integrated:{t:0,b:{t:2,i:[{t:3}],s:"SBC intégré"}},integratedNote:{t:0,b:{t:2,i:[{t:3,v:"Le SBC hôte est intégré à la carte mère "},{t:4,k:"board"},{t:3,v:"."}]}},selectPrompt:{t:0,b:{t:2,i:[{t:3}],s:"Sélectionnez une carte ou un MCU dans la carte pour l'inspecter."}},aria:{t:0,b:{t:2,i:[{t:3,v:"Carte de la machine : l'hôte et "},{t:4,k:"n"},{t:3,v:" MCU"}]}}}}};export{t as default};
